class Solution:
    def maximumBinaryString(self, binary: str) -> str:
        result = []
        for i in range(len(binary)):
            if binary[i] == '0' and i + 1 < len(binary) and binary[i + 1] == '0':
                result.append('1')
                result.append('0')
                i += 1
            else:
                result.append(binary[i])
        return ''.join(result)
